import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

const SideDrawer = () => {
  const [open, setOpen] = useState(false);
  const [profileImage, setProfileImage] = useState("");
  const navigate = useNavigate();

  const userId = localStorage.getItem("userId"); // must be set on login

  // Load profile image for current user
  useEffect(() => {
    const data = JSON.parse(localStorage.getItem(`profile_${userId}`)) || {};
    setProfileImage(data.image || "");
  }, [userId]);

  return (
    <>
      {/* ☰ Menu Button */}
      <button
        onClick={() => setOpen(!open)}
        style={{
          position: "fixed",
          top: "20px",
          left: "20px",
          zIndex: 1000,
          fontSize: "22px",
          background: "#333",
          color: "#fff",
          border: "none",
          padding: "10px 15px",
          borderRadius: "5px",
          cursor: "pointer",
        }}
      >
        ☰
      </button>

      {/* Top Right Profile Button / Image */}
      <div
        onClick={() => navigate("/dashboard/profile")}
        style={{
          position: "fixed",
          top: "20px",
          right: "20px",
          zIndex: 1000,
          cursor: "pointer",
        }}
      >
        <img
          src={profileImage || "https://via.placeholder.com/50"}
          alt="User Profile"
          style={{
            width: "50px",
            height: "50px",
            borderRadius: "50%",
            objectFit: "cover",
            border: "2px solid #ff6b6b",
          }}
        />
      </div>

      {/* Sidebar */}
      <div
        style={{
          position: "fixed",
          top: 0,
          left: open ? "0" : "-250px",
          width: "250px",
          height: "100%",
          background: "#222",
          color: "#fff",
          paddingTop: "60px",
          transition: "0.3s",
          zIndex: 999,
        }}
      >
        <ul style={{ listStyle: "none", padding: 0 }}>
          <li style={itemStyle} onClick={() => navigate("/")}>
            Home
          </li>
          <li style={itemStyle} onClick={() => navigate("/dashboard")}>
            Dashboard
          </li>
        </ul>
      </div>
    </>
  );
};

const itemStyle = {
  padding: "15px",
  cursor: "pointer",
  borderBottom: "1px solid #444",
};

export default SideDrawer;
